import { Injectable, inject, signal } from '@angular/core';
import { HttpClient } from '@angular/common/http';
import { firstValueFrom } from 'rxjs';
import { Castle, CountrySummary, RegionSummary } from '../models/castle.model';

@Injectable({ providedIn: 'root' })
export class CastleService {
  private http = inject(HttpClient);

  castles = signal<Castle[]>([]);
  loading = signal(false);

  private enrichedMap = signal<Map<string, Castle>>(new Map());
  private enrichedLoaded = signal(false);
  private enrichedLoading = false;

  async loadCastles(): Promise<void> {
    if (this.castles().length > 0) return;
    this.loading.set(true);
    try {
      const data = await firstValueFrom(this.http.get<Castle[]>('/assets/data/castles.json'));
      this.castles.set(data);
    } catch (err) {
      console.error('Failed to load castles:', err);
    } finally {
      this.loading.set(false);
    }
  }

  async loadEnrichedData(): Promise<void> {
    if (this.enrichedLoaded() || this.enrichedLoading) return;
    this.enrichedLoading = true;
    try {
      const delta = await firstValueFrom(this.http.get<Partial<Castle>[]>('/assets/data/castles_delta.json'));
      const merged = new Map<string, Castle>();
      const leanByCode = new Map(this.castles().map(c => [c.castle_code, c]));
      for (const d of delta) {
        if (!d.castle_code) continue;
        const lean = leanByCode.get(d.castle_code);
        if (lean) merged.set(d.castle_code, { ...lean, ...d });
      }
      this.enrichedMap.set(merged);
      this.enrichedLoaded.set(true);
    } catch (err) {
      console.error('Failed to load enriched castle data:', err);
    } finally {
      this.enrichedLoading = false;
    }
  }

  getEnrichedCastle(code: string): Castle | undefined {
    return this.enrichedMap().get(code);
  }

  getCastleByCode(code: string): Castle | undefined {
    return this.castles().find((c) => c.castle_code === code);
  }

  // castles_enriched.json is pre-sorted by score_total descending.
  // Methods below rely on this ordering; no runtime sort is needed except getTopByVisitors.

  getAllByScore(): Castle[] {
    return this.castles();
  }

  getTopByScore(count: number): Castle[] {
    return this.castles().slice(0, count);
  }

  getTopByVisitors(count: number): Castle[] {
    return this.castles()
      .slice()
      .sort((a, b) => (b.score_visitors ?? 0) - (a.score_visitors ?? 0))
      .slice(0, count);
  }

  // filter() preserves global score order, so the result is already top-N by score.
  getTopByCountry(country: string, count: number): Castle[] {
    return this.castles()
      .filter((c) => c.country?.toLowerCase() === country.toLowerCase())
      .slice(0, count);
  }

  getCastlesByCountry(country: string): Castle[] {
    return this.castles().filter((c) => c.country === country);
  }

  getCountries(): string[] {
    const countries = new Set(this.castles().map((c) => c.country));
    return [...countries].sort();
  }

  getCastleTypes(): string[] {
    const types = new Set(
      this.castles()
        .map((c) => c.castle_type)
        .filter(Boolean)
    );
    return [...types].sort();
  }

  getCastleConcepts(): string[] {
    const concepts = new Set(
      this.castles()
        .map((c) => c.castle_concept)
        .filter(Boolean)
    );
    return [...concepts].sort();
  }

  getCastleConditions(): string[] {
    const conditions = new Set(
      this.castles()
        .map((c) => c.condition)
        .filter(Boolean)
    );
    return [...conditions].sort();
  }

  /** Get the previous castle in the top-100 ranking (lower position number). */
  getPreviousCastle(code: string): Castle | undefined {
    const sorted = this.getAllByScore();
    const idx = sorted.findIndex((c) => c.castle_code === code);
    return idx > 0 ? sorted[idx - 1] : undefined;
  }

  /** Get the next castle in the top-100 ranking (higher position number). */
  getNextCastle(code: string): Castle | undefined {
    const sorted = this.getAllByScore();
    const idx = sorted.findIndex((c) => c.castle_code === code);
    return idx >= 0 && idx < sorted.length - 1 ? sorted[idx + 1] : undefined;
  }

  /** Get the previous castle within the same country (by position). */
  getPreviousCastleInCountry(code: string): Castle | undefined {
    const castle = this.getCastleByCode(code);
    if (!castle) return undefined;
    const countryCastles = this.castles()
      .filter((c) => c.country === castle.country && (c.score_total ?? 0) > 0)
      .sort((a, b) => (a.position ?? 999) - (b.position ?? 999));
    const idx = countryCastles.findIndex((c) => c.castle_code === code);
    return idx > 0 ? countryCastles[idx - 1] : undefined;
  }

  /** Get the next castle within the same country (by position). */
  getNextCastleInCountry(code: string): Castle | undefined {
    const castle = this.getCastleByCode(code);
    if (!castle) return undefined;
    const countryCastles = this.castles()
      .filter((c) => c.country === castle.country && (c.score_total ?? 0) > 0)
      .sort((a, b) => (a.position ?? 999) - (b.position ?? 999));
    const idx = countryCastles.findIndex((c) => c.castle_code === code);
    return idx >= 0 && idx < countryCastles.length - 1 ? countryCastles[idx + 1] : undefined;
  }

  getCountrySummaries(): CountrySummary[] {
    const map = new Map<string, { count: number; totalScore: number }>();
    for (const c of this.castles()) {
      if (!c.country) continue;
      const entry = map.get(c.country) ?? { count: 0, totalScore: 0 };
      entry.count++;
      entry.totalScore += c.score_total ?? 0;
      map.set(c.country, entry);
    }
    return [...map.entries()]
      .map(([country, { count, totalScore }]) => ({ country, castleCount: count, totalScore }))
      .sort((a, b) => b.totalScore - a.totalScore);
  }

  // Regions are scoped to a country — the same region name can appear in multiple countries.
  getRegionSummaries(country: string): RegionSummary[] {
    const map = new Map<string, { region_code: string; count: number; totalScore: number }>();
    for (const c of this.castles()) {
      if (!c.region || c.country !== country) continue;
      const entry = map.get(c.region) ?? { region_code: c.region_code || '', count: 0, totalScore: 0 };
      entry.count++;
      entry.totalScore += c.score_total ?? 0;
      map.set(c.region, entry);
    }
    return [...map.entries()]
      .map(([region, { region_code, count, totalScore }]) => ({ region, country, region_code, castleCount: count, totalScore }))
      .sort((a, b) => b.totalScore - a.totalScore);
  }

  getAreas(): string[] {
    const areas = new Set<string>();
    for (const c of this.castles()) {
      if (c.area) {
        for (const part of c.area.split(',')) {
          const trimmed = part.trim();
          if (trimmed) areas.add(trimmed);
        }
      }
    }
    return [...areas].sort();
  }

  getEras(): number[] {
    const eras = new Set(
      this.castles()
        .map((c) => c.era)
        .filter((e): e is number => e != null && e > 0)
    );
    return [...eras].sort((a, b) => a - b);
  }

}

import { Injectable, inject, signal } from '@angular/core';
import { HttpClient } from '@angular/common/http';
import { NoCastle } from '../models/castle.model';

@Injectable({ providedIn: 'root' })
export class NoCastleService {
  private http = inject(HttpClient);

  noCastles = signal<NoCastle[]>([]);
  loading = signal(false);

  loadNoCastles(): void {
    if (this.noCastles().length > 0) {
      return;
    }
    this.loading.set(true);
    this.http.get<NoCastle[]>('/assets/data/no_castles.json').subscribe({
      next: (data) => {
        this.noCastles.set(data);
        this.loading.set(false);
      },
      error: (err) => {
        console.error('Failed to load no_castles:', err);
        this.loading.set(false);
      },
    });
  }

  getByCode(code: string): NoCastle | undefined {
    return this.noCastles().find((c) => c.castle_code === code);
  }

  getAll(): NoCastle[] {
    return this.noCastles();
  }
}

import { inject, Injectable, PLATFORM_ID, signal } from '@angular/core';
import { isPlatformBrowser } from '@angular/common';

@Injectable({ providedIn: 'root' })
export class ThemeService {
  private readonly STORAGE_KEY = 'tk-theme';
  private readonly isBrowser = isPlatformBrowser(inject(PLATFORM_ID));

  isDark = signal(false);

  constructor() {
    if (!this.isBrowser) return;

    const stored = localStorage.getItem(this.STORAGE_KEY);
    const prefersDark = window.matchMedia('(prefers-color-scheme: dark)').matches;
    const dark = stored ? stored === 'dark' : prefersDark;
    this.isDark.set(dark);
    this.apply(dark);

    window.matchMedia('(prefers-color-scheme: dark)').addEventListener('change', e => {
      if (!localStorage.getItem(this.STORAGE_KEY)) {
        this.isDark.set(e.matches);
        this.apply(e.matches);
      }
    });
  }

  toggle(): void {
    if (!this.isBrowser) return;
    const dark = !this.isDark();
    this.isDark.set(dark);
    localStorage.setItem(this.STORAGE_KEY, dark ? 'dark' : 'light');
    this.apply(dark);
  }

  private apply(dark: boolean): void {
    document.documentElement.setAttribute('data-theme', dark ? 'dark' : 'light');
  }
}

import { Injectable, signal } from '@angular/core';

export type ViewMode = 'list' | 'grid' | 'map';

@Injectable({ providedIn: 'root' })
export class ViewModeService {
  private _mode = signal<ViewMode>('grid');
  readonly mode = this._mode.asReadonly();

  setMode(mode: ViewMode): void {
    this._mode.set(mode);
  }
}

