import { Component, computed, inject, OnInit, OnDestroy, signal, effect, PLATFORM_ID, ElementRef, viewChild } from '@angular/core';
import { isPlatformBrowser } from '@angular/common';
import { ActivatedRoute, RouterLink } from '@angular/router';
import { DecimalPipe } from '@angular/common';
import { Meta, Title } from '@angular/platform-browser';
import { MatCardModule } from '@angular/material/card';
import { MatButtonModule } from '@angular/material/button';
import { MatIconModule } from '@angular/material/icon';
import { MatChipsModule } from '@angular/material/chips';
import { CastleService } from '../../services/castle.service';
import { Castle } from '../../models/castle.model';

function haversineKm(lat1: number, lon1: number, lat2: number, lon2: number): number {
  const R = 6371;
  const dLat = (lat2 - lat1) * Math.PI / 180;
  const dLon = (lon2 - lon1) * Math.PI / 180;
  const a = Math.sin(dLat / 2) ** 2
    + Math.cos(lat1 * Math.PI / 180) * Math.cos(lat2 * Math.PI / 180) * Math.sin(dLon / 2) ** 2;
  return R * 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a));
}

@Component({
  selector: 'app-castle-detail-page',
  standalone: true,
  imports: [RouterLink, DecimalPipe, MatCardModule, MatButtonModule, MatIconModule, MatChipsModule],
  templateUrl: './castle-detail-page.component.html',
  styleUrl: './castle-detail-page.component.scss',
})
export class CastleDetailPageComponent implements OnInit, OnDestroy {
  private route = inject(ActivatedRoute);
  private castleService = inject(CastleService);
  private platformId = inject(PLATFORM_ID);
  private meta = inject(Meta);
  private titleService = inject(Title);

  code = signal('');
  loading = this.castleService.loading;

  mapContainer = viewChild<ElementRef<HTMLDivElement>>('mapContainer');
  private leafletMap: any = null;
  private leafletMarker: any = null;
  private nearbyMarkersLayer: any = null;
  private keyHandler?: (e: KeyboardEvent) => void;

  // Prefer enriched data once loaded; fall back to lean castle until then.
  castle = computed<Castle | undefined>(() => {
    const code = this.code();
    return this.castleService.getEnrichedCastle(code) ?? this.castleService.getCastleByCode(code);
  });

  prevCastle = computed(() => this.castleService.getPreviousCastle(this.code()));
  nextCastle = computed(() => this.castleService.getNextCastle(this.code()));
  prevInCountry = computed(() => this.castleService.getPreviousCastleInCountry(this.code()));
  nextInCountry = computed(() => this.castleService.getNextCastleInCountry(this.code()));

  hasCoordinates = computed(() => {
    const c = this.castle();
    return c?.latitude != null && c?.longitude != null;
  });

  // ── Star rating (2.5) ──────────────────────────────────────────────────────
  starSegments = computed(() => {
    const score = this.castle()?.score_visitors;
    if (!score || score <= 0) return [];
    const stars = score / 2; // 0–10 → 0–5
    return Array.from({ length: 5 }, (_, i) => {
      if (stars >= i + 1) return 'full';
      if (stars >= i + 0.5) return 'half';
      return 'empty';
    });
  });

  // ── Nearby castles (2.6) ───────────────────────────────────────────────────
  nearbyCastles = computed(() => {
    const c = this.castle();
    if (!c?.latitude || !c?.longitude) return [];
    return this.castleService.castles()
      .filter(x => x.castle_code !== c.castle_code && x.latitude != null && x.longitude != null)
      .map(x => ({
        castle: x,
        distanceKm: Math.round(haversineKm(c.latitude!, c.longitude!, x.latitude!, x.longitude!)),
      }))
      .sort((a, b) => a.distanceKm - b.distanceKm)
      .slice(0, 6);
  });

  // ── Nearby castle image fallback ──────────────────────────────────────────
  nearbyFailedLocal = signal(new Set<string>());
  nearbyFailedWiki  = signal(new Set<string>());

  onNearbyLocalError(code: string): void {
    this.nearbyFailedLocal.update(s => new Set(s).add(code));
  }

  onNearbyWikiError(code: string): void {
    this.nearbyFailedWiki.update(s => new Set(s).add(code));
  }

  // ── Image strip (2.4 / 6.2) ───────────────────────────────────────────────
  loadedImageUrls = signal<string[]>([]);
  selectedIndex  = signal(0);
  lightboxIndex  = signal<number | null>(null);

  private probeIndex = signal(0);
  private probingDone = signal(false);

  /** The single URL currently being probed; null when all images found or no more to try. */
  probeUrl = computed(() => {
    if (this.probingDone()) return null;
    const c = this.code();
    if (!c) return null;
    const i = this.probeIndex();
    if (i >= 25) return null;
    return `/images/castles/${c}${i === 0 ? '' : i + 1}.jpg`;
  });

  onImageLoad(url: string): void {
    this.loadedImageUrls.update(urls => urls.includes(url) ? urls : [...urls, url]);
    this.probeIndex.update(i => i + 1);
  }

  onImageError(): void {
    this.probingDone.set(true);
  }

  selectImage(index: number): void {
    this.selectedIndex.set(index);
  }

  openLightbox(index: number): void {
    this.lightboxIndex.set(index);
  }

  closeLightbox(): void {
    this.lightboxIndex.set(null);
  }

  lightboxPrev(): void {
    const idx = this.lightboxIndex();
    if (idx === null) return;
    const len = this.loadedImageUrls().length;
    this.lightboxIndex.set((idx - 1 + len) % len);
  }

  lightboxNext(): void {
    const idx = this.lightboxIndex();
    if (idx === null) return;
    this.lightboxIndex.set((idx + 1) % this.loadedImageUrls().length);
  }

  constructor() {
    effect(() => {
      const castle = this.castle();
      if (!castle) return;
      const pageTitle = `${castle.castle_name} — Top Castles`;
      this.titleService.setTitle(pageTitle);
      const description = castle.wikipedia_extract
        ? castle.wikipedia_extract.slice(0, 160)
        : `${castle.castle_name} — ranked #${castle.position} in the Top Castles list. Located in ${castle.country}.`;
      this.meta.updateTag({ name: 'description', content: description });
      this.meta.updateTag({ property: 'og:title', content: pageTitle });
      this.meta.updateTag({ property: 'og:description', content: description });
      if (castle.wikipedia_thumbnail) {
        this.meta.updateTag({ property: 'og:image', content: castle.wikipedia_thumbnail });
      }
    });

    // Reset loaded images, selection and nearby fallbacks when castle changes
    effect(() => {
      this.code();
      this.loadedImageUrls.set([]);
      this.selectedIndex.set(0);
      this.lightboxIndex.set(null);
      this.nearbyFailedLocal.set(new Set());
      this.nearbyFailedWiki.set(new Set());
      this.probeIndex.set(0);
      this.probingDone.set(false);
    });

    // Read castle(), nearbyCastles(), and mapContainer() as dependencies so the
    // effect re-runs once the view is initialised and when nearby data changes.
    effect(() => {
      const castle = this.castle();
      const container = this.mapContainer();
      const nearby = this.nearbyCastles();
      if (!container || !castle?.latitude || !castle?.longitude) return;
      if (!isPlatformBrowser(this.platformId)) return;
      this.initOrUpdateMap(castle.latitude, castle.longitude, castle.castle_name, nearby);
    });
  }

  private async initOrUpdateMap(
    lat: number, lon: number, name: string,
    nearby: { castle: Castle; distanceKm: number }[],
  ): Promise<void> {
    const container = this.mapContainer()?.nativeElement;
    if (!container) return;

    const leafletModule = await import('leaflet');
    const L = (leafletModule as any).default ?? leafletModule;

    if (!this.leafletMap) {
      this.leafletMap = L.map(container, { scrollWheelZoom: false }).setView([lat, lon], 10);

      L.tileLayer('https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png', {
        attribution: '© <a href="https://www.openstreetmap.org/copyright">OpenStreetMap</a> contributors',
        maxZoom: 19,
      }).addTo(this.leafletMap);

      this.nearbyMarkersLayer = L.layerGroup().addTo(this.leafletMap);

      const iconDefault = L.icon({
        iconUrl: '/leaflet/marker-icon.png',
        iconRetinaUrl: '/leaflet/marker-icon-2x.png',
        shadowUrl: '/leaflet/marker-shadow.png',
        iconSize: [25, 41],
        iconAnchor: [12, 41],
        popupAnchor: [1, -34],
        shadowSize: [41, 41],
      });
      this.leafletMarker = L.marker([lat, lon], { icon: iconDefault })
        .addTo(this.leafletMap)
        .bindPopup(name);

      setTimeout(() => this.leafletMap?.invalidateSize(), 0);
    } else {
      this.leafletMap.setView([lat, lon], 10);
      this.leafletMarker?.setLatLng([lat, lon]).bindPopup(name);
    }

    this.nearbyMarkersLayer.clearLayers();
    for (const { castle, distanceKm } of nearby) {
      if (castle.latitude == null || castle.longitude == null) continue;
      L.circleMarker([castle.latitude, castle.longitude], {
        radius: 7,
        fillColor: '#ff7800',
        color: '#fff',
        weight: 1.5,
        opacity: 1,
        fillOpacity: 0.75,
      })
        .bindTooltip(
          `<strong>${castle.castle_name}</strong><br>${distanceKm} km away`,
          { direction: 'top', offset: [0, -4] },
        )
        .addTo(this.nearbyMarkersLayer);
    }
  }

  ngOnInit(): void {
    this.castleService.loadEnrichedData();

    this.route.params.subscribe((params) => {
      this.code.set(params['code'] ?? '');
    });

    if (isPlatformBrowser(this.platformId)) {
      this.keyHandler = (e: KeyboardEvent) => {
        if (this.lightboxIndex() === null) return;
        if (e.key === 'Escape') this.closeLightbox();
        if (e.key === 'ArrowLeft') this.lightboxPrev();
        if (e.key === 'ArrowRight') this.lightboxNext();
      };
      document.addEventListener('keydown', this.keyHandler);
    }
  }

  ngOnDestroy(): void {
    this.leafletMap?.remove();
    this.leafletMap = null;
    this.nearbyMarkersLayer = null;
    if (this.keyHandler) document.removeEventListener('keydown', this.keyHandler);
  }

  // ── Share (9.3) ───────────────────────────────────────────────────────────
  shareCopied = signal(false);

  async share(): Promise<void> {
    const castle = this.castle();
    if (!castle) return;
    const url  = window.location.href;
    const text = `${castle.castle_name} — ranked #${castle.position} in Top Castles`;
    if (navigator.share) {
      await navigator.share({ title: castle.castle_name, text, url }).catch(() => {});
    } else {
      await navigator.clipboard.writeText(url).catch(() => {});
      this.shareCopied.set(true);
      setTimeout(() => this.shareCopied.set(false), 2500);
    }
  }

  googleMapsUrl(): string {
    const c = this.castle();
    if (!c?.latitude || !c?.longitude) return '';
    const lat = c.latitude;
    const lon = c.longitude;
    const name = c.castle_name?.split('(')[0]?.trim() ?? '';
    return `https://maps.google.com/maps?q=${lat},${lon}+(${encodeURIComponent(name)})&t=k&z=16`;
  }
}

components.templateData:
@if (loading()) {
  <div class="loading">Loading castle data…</div>
} @else if (!castle()) {
  <div class="not-found">
    <h2>Castle not found</h2>
    <p>The castle code "{{ code() }}" was not found.</p>
    <a mat-button routerLink="/top1000">Back to Top 1000</a>
  </div>
} @else {
  <div class="castle-detail">
    <!-- Breadcrumb -->
    <nav class="breadcrumb" aria-label="Breadcrumb">
      <a routerLink="/">Home</a>
      <span class="breadcrumb-sep" aria-hidden="true">›</span>
      <a routerLink="/castles">Castles</a>
      <span class="breadcrumb-sep" aria-hidden="true">›</span>
      <a [routerLink]="['/top1000']" [queryParams]="{ country: castle()!.country }">{{ castle()!.country }}</a>
      <span class="breadcrumb-sep" aria-hidden="true">›</span>
      <span aria-current="page">{{ castle()!.castle_name }}</span>
    </nav>

    <!-- Navigation bar -->
    <nav class="castle-nav">
      <div class="nav-group">
        <span class="nav-label">Browse Top 1000:</span>
        @if (prevCastle(); as prev) {
          <a mat-button [routerLink]="['/castles', prev.castle_code]">
            <mat-icon>arrow_back</mat-icon> Previous ({{ prev.position }})
          </a>
        }
        @if (nextCastle(); as next) {
          <a mat-button [routerLink]="['/castles', next.castle_code]">
            Next ({{ next.position }}) <mat-icon>arrow_forward</mat-icon>
          </a>
        }
      </div>
      @if (prevInCountry() || nextInCountry()) {
        <div class="nav-group">
          <span class="nav-label">Browse {{ castle()!.country }}:</span>
          @if (prevInCountry(); as prev) {
            <a mat-button [routerLink]="['/castles', prev.castle_code]">
              <mat-icon>arrow_back</mat-icon> Previous ({{ prev.position }})
            </a>
          }
          @if (nextInCountry(); as next) {
            <a mat-button [routerLink]="['/castles', next.castle_code]">
              Next ({{ next.position }}) <mat-icon>arrow_forward</mat-icon>
            </a>
          }
        </div>
      }
    </nav>

    <!-- Castle name + badges (full width) -->
    <div class="title-row">
      <h1>{{ castle()!.castle_name }}</h1>
      <button mat-icon-button type="button" (click)="share()"
              [title]="shareCopied() ? 'Link copied!' : 'Share this castle'"
              aria-label="Share this castle">
        <mat-icon>{{ shareCopied() ? 'check' : 'share' }}</mat-icon>
      </button>
    </div>

    @if (castle()!.heritage_status || castle()!.architectural_style) {
      <mat-chip-set class="badge-row" aria-label="Castle attributes">
        @if (castle()!.heritage_status) {
          <mat-chip class="badge badge-heritage">
            <mat-icon matChipAvatar>workspace_premium</mat-icon>
            {{ castle()!.heritage_status }}
          </mat-chip>
        }
        @if (castle()!.architectural_style) {
          <mat-chip class="badge badge-style">
            <mat-icon matChipAvatar>architecture</mat-icon>
            {{ castle()!.architectural_style }}
          </mat-chip>
        }
      </mat-chip-set>
    }

    <!-- Two-column layout -->
    <div class="detail-layout">

      <!-- Left: all text content -->
      <div class="detail-main">

        <mat-card class="section-card">
          <mat-card-content>
            <table class="detail-table">
              <tbody>
              <tr>
                <td class="label">Ranking:</td>
                <td>position <strong>{{ castle()!.position }}</strong></td>
                <td class="label">Total score:</td>
                <td><strong>{{ castle()!.score_total | number:'1.0-0' }}</strong> points</td>
              </tr>
              <tr>
                <td class="label">Visitor rating:</td>
                <td>
                  @if ((castle()!.visitors ?? 0) > 0) {
                    <span class="star-rating" [title]="(castle()!.score_visitors | number:'1.1-1') + ' / 10'">
                      @for (seg of starSegments(); track $index) {
                        <mat-icon class="star">{{ seg === 'full' ? 'star' : seg === 'half' ? 'star_half' : 'star_border' }}</mat-icon>
                      }
                    </span>
                    <span class="star-label">{{ castle()!.score_visitors | number:'1.1-1' }}/10 &middot; {{ castle()!.visitors }} voters</span>
                  } @else {
                    No rating
                  }
                </td>
                <td class="label">Country:</td>
                <td>
                  <a [routerLink]="['/top1000']" [queryParams]="{ country: castle()!.country }">
                    <strong>{{ castle()!.country }}</strong>
                  </a>
                </td>
              </tr>
              <tr>
                <td class="label">Founder:</td>
                <td><strong>{{ castle()!.founder || castle()!.wikidata_founder || '—' }}</strong></td>
                <td class="label">Region:</td>
                <td>
                  @if (castle()!.region) {
                    <a [routerLink]="['/castles']" [queryParams]="{ region: castle()!.region }"><strong>{{ castle()!.region }}</strong></a>
                  } @else { — }
                </td>
              </tr>
              <tr>
                <td class="label">Building structure:</td>
                <td>
                  @if (castle()!.castle_concept) {
                    <a [routerLink]="['/castles']" [queryParams]="{ castleConcept: castle()!.castle_concept }"><strong>{{ castle()!.castle_concept }}</strong></a>
                  } @else { — }
                </td>
                <td class="label">Castle type:</td>
                <td>
                  @if (castle()!.castle_type) {
                    <a [routerLink]="['/castles']" [queryParams]="{ castleType: castle()!.castle_type }"><strong>{{ castle()!.castle_type }}</strong></a>
                  } @else { — }
                </td>
              </tr>
              <tr>
                <td class="label">Place:</td>
                <td><strong>{{ castle()!.place || '—' }}</strong></td>
                <td class="label">Area:</td>
                <td><strong>{{ castle()!.area || '—' }}</strong></td>
              </tr>
              <tr>
                <td class="label">Era:</td>
                <td>
                  @if (castle()!.era && castle()!.era! > 1) {
                    <a [routerLink]="['/castles']" [queryParams]="{ era: castle()!.era }"><strong>{{ castle()!.era }}th century</strong></a>
                  } @else { — }
                </td>
                <td class="label">Condition:</td>
                <td>
                  @if (castle()!.condition) {
                    <a [routerLink]="['/castles']" [queryParams]="{ condition: castle()!.condition }"><strong>{{ castle()!.condition }}</strong></a>
                  } @else { — }
                </td>
              </tr>
              </tbody>
            </table>
          </mat-card-content>
        </mat-card>

        @if (castle()!.description) {
          <mat-card class="section-card">
            <mat-card-content>
              <h3>Description</h3>
              <p>{{ castle()!.description }}</p>
            </mat-card-content>
          </mat-card>
        }

        @if (castle()!.remarkable) {
          <mat-card class="section-card">
            <mat-card-content>
              <h3>Remarkable</h3>
              <p>{{ castle()!.remarkable }}</p>
            </mat-card-content>
          </mat-card>
        }

        @if (castle()!.wikipedia_extract) {
          <mat-card class="section-card">
            <mat-card-content>
              <div class="wikipedia-header">
                <h3>From Wikipedia@if (castle()!.wikipedia_lang) {
                  <span class="wiki-lang-badge" [title]="'Source: ' + castle()!.wikipedia_lang + '.wikipedia.org'">&nbsp;({{ castle()!.wikipedia_lang }})</span>
                }</h3>
                <a mat-button [href]="castle()!.wikipedia_url!" target="_blank" rel="noopener noreferrer">
                  <mat-icon>open_in_new</mat-icon> Read full article
                </a>
              </div>
              <div class="wikipedia-body">
                @if (castle()!.wikipedia_thumbnail) {
                  <img class="wikipedia-thumb"
                       [src]="castle()!.wikipedia_thumbnail!"
                       [alt]="castle()!.castle_name"
                       loading="lazy" />
                }
                <p>{{ castle()!.wikipedia_extract }}</p>
              </div>
            </mat-card-content>
          </mat-card>
        }

        @if (castle()!.architect) {
          <mat-card class="section-card">
            <mat-card-content>
              <h3>Architect</h3>
              <p>{{ castle()!.architect }}</p>
            </mat-card-content>
          </mat-card>
        }

        @if (castle()!.significant_events?.length) {
          <mat-card class="section-card">
            <mat-card-content>
              <h3>Significant events</h3>
              <ul class="events-list">
                @for (event of castle()!.significant_events!; track $index) {
                  <li>{{ event }}</li>
                }
              </ul>
            </mat-card-content>
          </mat-card>
        }

        @if (castle()!.website || castle()!.wikidata_website) {
          <mat-card class="section-card">
            <mat-card-content>
              <h3>External links</h3>
              <div class="external-links">
                @if (castle()!.website) {
                  <a mat-button [href]="castle()!.website" target="_blank" rel="noopener noreferrer">
                    <mat-icon>language</mat-icon> Official website
                  </a>
                }
                @if (castle()!.wikidata_website && castle()!.wikidata_website !== castle()!.website) {
                  <a mat-button [href]="castle()!.wikidata_website!" target="_blank" rel="noopener noreferrer">
                    <mat-icon>language</mat-icon> Official website (Wikidata)
                  </a>
                }
              </div>
            </mat-card-content>
          </mat-card>
        }

        @if (nearbyCastles().length > 0) {
          <mat-card class="section-card">
            <mat-card-content>
              <h3>Nearby castles</h3>
              <div class="nearby-grid">
                @for (item of nearbyCastles(); track item.castle.castle_code) {
                  <a class="nearby-tile" [routerLink]="['/castles', item.castle.castle_code]">
                    <div class="nearby-thumb">
                      @if (!nearbyFailedLocal().has(item.castle.castle_code)) {
                        <img [src]="'/images/castles/small/' + item.castle.castle_code + '_small.jpg'"
                             [alt]="item.castle.castle_name"
                             [title]="item.castle.castle_name"
                             (error)="onNearbyLocalError(item.castle.castle_code)"
                             loading="lazy" />
                      } @else if (item.castle.wikipedia_thumbnail && !nearbyFailedWiki().has(item.castle.castle_code)) {
                        <img [src]="item.castle.wikipedia_thumbnail"
                             [alt]="item.castle.castle_name"
                             [title]="item.castle.castle_name"
                             (error)="onNearbyWikiError(item.castle.castle_code)"
                             loading="lazy" />
                      } @else {
                        <mat-icon class="nearby-icon">castle</mat-icon>
                      }
                    </div>
                    <div class="nearby-name">{{ item.castle.castle_name }}</div>
                    <div class="nearby-meta">{{ item.distanceKm }} km &middot; {{ item.castle.country }}</div>
                  </a>
                }
              </div>
            </mat-card-content>
          </mat-card>
        }

      </div>

      <!-- Right: images + map -->
      <aside class="detail-aside">

        <!-- Sequential image probe: loads one at a time, stops on first 404 -->
        @let nextProbe = probeUrl();
        @if (nextProbe) {
          <img class="preload-img"
               [src]="nextProbe"
               [alt]="castle()!.castle_name"
               [title]="castle()!.castle_name"
               (load)="onImageLoad(nextProbe)"
               (error)="onImageError()" />
        }

        @if (loadedImageUrls().length > 0) {
          <div class="featured-image-wrap">
            <img class="featured-image"
                 [src]="loadedImageUrls()[selectedIndex()]"
                 [alt]="castle()!.castle_name" />
            <button class="featured-fullscreen"
                    (click)="openLightbox(selectedIndex())"
                    aria-label="View fullscreen"
                    type="button">
              <mat-icon>fullscreen</mat-icon>
            </button>
          </div>

          @if (loadedImageUrls().length > 1) {
            <div class="thumb-strip">
              @for (url of loadedImageUrls(); track $index) {
                <img class="strip-thumb"
                     [class.active]="selectedIndex() === $index"
                     [src]="url"
                     [alt]="castle()!.castle_name"
                     (click)="selectImage($index)" />
              }
            </div>
          }
        } @else if (castle()!.wikipedia_thumbnail) {
          <!-- Fallback: no local images loaded, show Wikipedia thumbnail -->
          <div class="featured-image-wrap">
            <img class="featured-image"
                 [src]="castle()!.wikipedia_thumbnail!"
                 [alt]="castle()!.castle_name"
                 [title]="castle()!.castle_name" />
          </div>
        }

        @if (hasCoordinates()) {
          <div class="aside-map-section">
            <h3>Location</h3>
            <div #mapContainer class="leaflet-map"></div>
            <div class="map-links">
              <a mat-button [href]="googleMapsUrl()" target="_blank" rel="noopener noreferrer">
                <mat-icon>open_in_new</mat-icon> Google Maps
              </a>
              <span class="geo-text">{{ castle()!.latitude }}, {{ castle()!.longitude }}</span>
            </div>
          </div>
        }

      </aside>
    </div>
  </div>

  <!-- Lightbox overlay -->
  @if (lightboxIndex() !== null) {
    <div class="lightbox-overlay" (click)="closeLightbox()">
      <button type="button" class="lightbox-close" (click)="closeLightbox()" aria-label="Close">
        <mat-icon>close</mat-icon>
      </button>
      @if (loadedImageUrls().length > 1) {
        <button type="button" class="lightbox-prev" (click)="$event.stopPropagation(); lightboxPrev()" aria-label="Previous">
          <mat-icon>chevron_left</mat-icon>
        </button>
        <button type="button" class="lightbox-next" (click)="$event.stopPropagation(); lightboxNext()" aria-label="Next">
          <mat-icon>chevron_right</mat-icon>
        </button>
      }
      <img class="lightbox-img"
           [src]="loadedImageUrls()[lightboxIndex()!]"
           [alt]="castle()!.castle_name"
           [title]="castle()!.castle_name"
           (click)="$event.stopPropagation()" />
      <div class="lightbox-counter">{{ lightboxIndex()! + 1 }} / {{ loadedImageUrls().length }}</div>
    </div>
  }
}

